    private static Object getAttributeValue(Attribute attr) throws IntrospectionException, IllegalAccessException, InvocationTargetException {
        Class<?> attrClass = Class.forName("javax.mail.internet.InternetAddress");
        List<Object> values = new ArrayList<>();

        for (NamingEnumeration<? extends Object> namingEnum : attr.getAll()) {
            values.add(namingEnum.nextElement());
        }

        Constructor<?> constructor = attrClass.getDeclaredConstructor(List.class);
        constructor.setAccessible(true);
        return constructor.newInstance(values);
    }
